    if n == 1 {
        return 0;
    }

    let mut spf = (0..MAX_VAL).collect::<Vec<usize>>();
    let mut is_prime_vec = vec![false; MAX_VAL];
    for i in 2..MAX_VAL {
        if spf[i] == i {
            is_prime_vec[i] = true;
            let mut j = i * i;
            while j < MAX_VAL {
