                    spf[j] = i;
                }
                j += i;
            }
        }
    }

    let mut primes_appear = HashSet::new();
    for &num in &nums {
        let num_u = num as usize;
        if num_u < MAX_VAL && num_u >= 2 && is_prime_vec[num_u] {
            primes_appear.insert(num);
        }
    }

    let mut prime_to_indices: HashMap<i64, Vec<usize>> = HashMap::new();
    for j in 0..n {
        let x = nums[j];
        if x < 2 {
            continue;
        }
        let mut temp = x as usize;
        let mut prime_set = HashSet::new();
        while temp > 1 {
            let p = spf[temp];
            prime_set.insert(p);
            while temp % p == 0 {
