            }
        }
        for p in prime_set {
            let p_i64 = p as i64;
            if primes_appear.contains(&p_i64) {
                prime_to_indices.entry(p_i64).or_insert_with(Vec::new).push(j);
            }
        }
    }

    let mut visited = vec![false; n];
    let mut propagated_vec = vec![false; MAX_VAL];
    let mut queue = VecDeque::new();
    queue.push_back((0, 0));
    visited[0] = true;

    while let Some((i, steps)) = queue.pop_front() {
        if i == n - 1 {
            return steps;
        }

        if i > 0 {
            let prev_index = i - 1;
            if !visited[prev_index] {
                visited[prev_index] = true;
                queue.push_back((prev_index, steps + 1));
            }
        }

        if i < n - 1 {
            let next_index = i + 1;
            if !visited[next_index] {
                visited[next_index] = true;
                queue.push_back((next_index, steps + 1));
            }
        }

        let num = nums[i];
        if num < 2 {
            continue;
        }
        let num_usize = num as usize;
        if num_usize < MAX_VAL && is_prime_vec[num_usize] {
            if propagated_vec[num_usize] {
                continue;
            }
            propagated_vec[num_usize] = true;
            if let Some(indices) = prime_to_indices.get(&num) {
                for &j in indices {
                    if j != i && !visited[j] {
                        visited[j] = true;
                        queue.push_back((j, steps + 1));
                    }
                }
            }
        }
    }

    -1
}
