pub fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    if n == 1 {
        return 0;
    }

    let mut is_prime = vec![true; MAX_VAL + 1];
    let mut spf = vec![0; MAX_VAL + 1];
