        for &p in primes.iter() {
            let j = p * i;
            if j > MAX_VAL {
                break;
            }
            is_prime[j] = false;
            spf[j] = p;
            if i % p == 0 {
                break;
            }
        }
    }

    let mut primes_in_array = HashSet::new();
    for &num in &nums {
        if num < 2 {
            continue;
        }
        if num <= MAX_VAL as i64 {
            let idx = num as usize;
            if is_prime[idx] {
                primes_in_array.insert(num);
            }
        }
    }

    let mut prime_indices: HashMap<i64, Vec<usize>> = HashMap::new();
    for (j, &num) in nums.iter().enumerate() {
        if num < 2 {
            continue;
        }
        let mut factors = HashSet::new();
        let mut x = num as usize;
        while x > 1 {
            let p = spf[x];
            factors.insert(p as i64);
            while x % p == 0 {
                x /= p;
            }
        }
        for p in factors {
            if primes_in_array.contains(&p) {
                prime_indices.entry(p).or_insert_with(Vec::new).push(j);
            }
        }
    }

    let mut dist = vec![-1_i64; n];
    dist[0] = 0;
    let mut queue = VecDeque::new();
    queue.push_back(0);
    let mut processed_primes = HashSet::new();

    while let Some(u) = queue.pop_front() {
        if u == n - 1 {
            return dist[u];
        }

        for neighbor in [u as i64 + 1, u as i64 - 1].iter() {
            let v = *neighbor;
            if v >= 0 && v < n as i64 {
                let v = v as usize;
